import{_ as o,C as r,o as s,c as n,ag as t,E as i}from"./chunks/framework.DLWhSH9p.js";const b=JSON.parse('{"title":"Resources","description":"","frontmatter":{},"headers":[],"relativePath":"guide/resources.md","filePath":"guide/resources.md"}'),d={name:"guide/resources.md"};function l(c,e,u,h,p,g){const a=r("SchemeImage");return s(),n("div",null,[e[0]||(e[0]=t('<h1 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h1><p>The Resources panel searches 14 royalty-free sources for video clips, images, audio, and reference material to use in your productions. Resources are <strong>user-owned</strong> and <strong>channel-assigned</strong> — they belong to you, not to a single channel, and can be assigned to multiple channels.</p><h2 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Types</th><th>API Key?</th></tr></thead><tbody><tr><td>Pexels</td><td>video, image</td><td>Yes (<code>PEXELS_API_KEY</code>)</td></tr><tr><td>Pixabay</td><td>video, image</td><td>Yes (<code>PIXABAY_API_KEY</code>)</td></tr><tr><td>Unsplash</td><td>image</td><td>Yes (<code>UNSPLASH_ACCESS_KEY</code>)</td></tr><tr><td>Freesound</td><td>audio</td><td>Yes (<code>FREESOUND_API_KEY</code>)</td></tr><tr><td>Europeana</td><td>image, video, audio</td><td>Yes (<code>EUROPEANA_API_KEY</code>)</td></tr><tr><td>NASA</td><td>video, image</td><td>No (free)</td></tr><tr><td>Wikipedia</td><td>reference</td><td>No (free)</td></tr><tr><td>arXiv</td><td>reference</td><td>No (free)</td></tr><tr><td>Smithsonian</td><td>image, reference</td><td>No (free)</td></tr><tr><td>Library of Congress</td><td>image, reference</td><td>No (free)</td></tr><tr><td>Internet Archive</td><td>video, audio, reference</td><td>No (free)</td></tr><tr><td>Wikimedia Commons</td><td>image, video, audio</td><td>No (free)</td></tr><tr><td>Met Museum</td><td>image</td><td>No (free)</td></tr><tr><td>Web Search (SearXNG)</td><td>video, image, audio</td><td>No (self-hosted)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>9 of 14 sources work without any API key. You can start researching immediately.</p></div><h2 id="searching" tabindex="-1">Searching <a class="header-anchor" href="#searching" aria-label="Permalink to &quot;Searching&quot;">​</a></h2><ol><li>Enter a search query</li><li>Select content type: <strong>Video</strong>, <strong>Image</strong>, <strong>Audio</strong>, or <strong>Research</strong></li><li>Optionally filter by <strong>source</strong> and <strong>license</strong> (CC0, CC-BY, etc.)</li><li>Results appear with thumbnails, titles, and source badges</li></ol>',7)),i(a,{name:"resources-search",alt:"Resource Search"}),e[1]||(e[1]=t(`<h2 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h2><p>Click a result to preview:</p><ul><li><strong>Video</strong> — trimmed to 5 seconds via ffmpeg</li><li><strong>Audio</strong> — trimmed to 10 seconds</li><li><strong>Images</strong> — full preview</li></ul><p>Previews are proxied through the backend to avoid CORS issues.</p><h2 id="download" tabindex="-1">Download <a class="header-anchor" href="#download" aria-label="Permalink to &quot;Download&quot;">​</a></h2><p>Click <strong>Download</strong> to save media to your resources library. Downloads are <strong>auto-assigned</strong> to whichever channel context you&#39;re currently browsing. Each download stores a <code>.meta.json</code> sidecar with source, license, attribution, and original URL.</p><p>Files are deduplicated by <strong>SHA-256 hash</strong> via the <code>resource_files</code> database table — uploading or downloading the same file twice reuses the existing record.</p><h2 id="upload" tabindex="-1">Upload <a class="header-anchor" href="#upload" aria-label="Permalink to &quot;Upload&quot;">​</a></h2><p>Drag-and-drop files directly into the Resources panel:</p><ul><li>Video clips, images, animations, sound effects</li><li>Up to 500MB per file</li><li>Automatically detected file type</li></ul><h2 id="library" tabindex="-1">Library <a class="header-anchor" href="#library" aria-label="Permalink to &quot;Library&quot;">​</a></h2><p>The <strong>Library</strong> tab shows all your downloaded and uploaded resources. Resources is a <strong>user-level</strong> section — reach it via the <strong>Resources</strong> link in the top chrome&#39;s right rail. Since resources belong to you and can span multiple channels, they aren&#39;t nested under any single channel.</p><h2 id="channel-assignment" tabindex="-1">Channel Assignment <a class="header-anchor" href="#channel-assignment" aria-label="Permalink to &quot;Channel Assignment&quot;">​</a></h2><p>Resources use a many-to-many model via the <code>resource_assignments</code> junction table. A single resource can be assigned to multiple channels, and a channel can reference many resources. Downloads auto-assign to the current channel context, but you can manage assignments manually.</p><h2 id="ai-content-attribution" tabindex="-1">AI Content Attribution <a class="header-anchor" href="#ai-content-attribution" aria-label="Permalink to &quot;AI Content Attribution&quot;">​</a></h2><p>Resources generated by AI services (ComfyUI images, TTS audio, MusicGen music) are automatically tagged with attribution metadata:</p><ul><li>An <strong>&quot;AI Generated&quot;</strong> purple badge appears on these files in the library</li><li><code>.meta.json</code> sidecars include <code>aiGenerated</code>, <code>generator</code>, <code>generatedBy</code>, and <code>marketplaceRestriction</code> fields</li><li>Default marketplace restriction is <code>free-with-attribution</code> -- you can use AI-generated assets freely but should credit the generator</li></ul><p>This helps you track which assets are AI-generated when preparing attribution for YouTube descriptions or other platforms.</p><h2 id="attribution" tabindex="-1">Attribution <a class="header-anchor" href="#attribution" aria-label="Permalink to &quot;Attribution&quot;">​</a></h2><p>Click <strong>Generate Attribution</strong> to create a text block listing all resources used for a script — source names, licenses, and links. Copy-paste into your YouTube description.</p><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Media Credits:</span></span>
<span class="line"><span>• &quot;Cosmic Nebula&quot; — NASA (Public Domain)</span></span>
<span class="line"><span>• &quot;Ocean Waves&quot; — Pexels, by John Doe (Pexels License)</span></span>
<span class="line"><span>• &quot;Ambient Piano&quot; — Freesound, by composer123 (CC BY 4.0)</span></span>
<span class="line"><span>• &quot;Milky Way Galaxy&quot; — Wikimedia Commons (CC BY-SA 3.0)</span></span></code></pre></div>`,22))])}const f=o(d,[["render",l]]);export{b as __pageData,f as default};
